# Basic exception handling
def divide_numbers(a, b):
    try:
        result = a / b
        return result
    except ZeroDivisionError:
        print("Error: Cannot divide by zero")
        return None
    except TypeError:
        print("Error: Both arguments must be numbers")
        return None
    finally:
        print("Division operation completed")

import pandas as pd

# Sample data
df = pd.DataFrame({
    'department': ['Sales', 'HR', 'Sales', 'IT', 'HR'],
    'employee': ['Alice', 'Bob', 'Charlie', 'Dave', 'Eve'],
    'salary': [50000, 60000, 55000, 65000, 62000],
    'bonus': [5000, 3000, 4500, 7000, 3500]
})

# Group by one column and calculate mean
dept_avg = df.groupby('department').mean()

# Group by and apply multiple aggregations
dept_stats = df.groupby('department').agg({
    'salary': ['mean', 'min', 'max', 'count'],
    'bonus': ['mean', 'sum']
})

# Apply custom function to each group
def salary_range(x):
    return x.max() - x.min()

df.groupby('department')['salary'].apply(salary_range)

# get() with default value - avoids KeyError
config = {'host': 'localhost', 'port': 5432}
db_name = config.get('database', 'default_db')  # 'default_db'
host = config.get('host', '127.0.0.1')           # 'localhost'

